import React, { useState, useEffect } from "react";
import "./App.css";

function App() {
  const [tab, setTab] = useState("html");

  const [html, setHtml] = useState("<h1>Hello</h1>");
  const [css, setCss] = useState("h1{color:red}");
  const [js, setJs] = useState("");

  // Load
  useEffect(() => {
    const data = JSON.parse(localStorage.getItem("project"));
    if (data) {
      setHtml(data.html || "");
      setCss(data.css || "");
      setJs(data.js || "");
    }
  }, []);

  // Auto Save
  useEffect(() => {
    localStorage.setItem("project", JSON.stringify({ html, css, js }));
  }, [html, css, js]);

  const clearCode = () => {
    setHtml("");
    setCss("");
    setJs("");
  };

  const output = `
    <html>
      <style>${css}</style>
      <body>
        ${html}
        <script>${js}<\/script>
      </body>
    </html>
  `;

  return (
    <div className="app">

      {/* TOP */}
      <div className="topbar">
        <h2>🔥 CodeSnip Pro</h2>
        <div>
          <button onClick={clearCode}>Clear</button>
        </div>
      </div>

      {/* TABS */}
      <div className="tabs">
        <button onClick={() => setTab("html")}>HTML</button>
        <button onClick={() => setTab("css")}>CSS</button>
        <button onClick={() => setTab("js")}>JS</button>
      </div>

      {/* MAIN */}
      <div className="container">

        {/* EDITOR */}
        <div className="editor">
          <textarea
            value={tab === "html" ? html : tab === "css" ? css : js}
            onChange={(e) => {
              if (tab === "html") setHtml(e.target.value);
              if (tab === "css") setCss(e.target.value);
              if (tab === "js") setJs(e.target.value);
            }}
          />
        </div>

        {/* PREVIEW */}
        <div className="preview">
          <iframe srcDoc={output} title="preview" sandbox="allow-scripts" />
        </div>

      </div>
    </div>
  );
}

export default App;
